import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const g=JSON.parse('{"title":"Guide: Knowledge Indexing & Portals","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/knowledge-indexing-portals.md","filePath":"guides/knowledge-indexing-portals.md","lastUpdated":1782929962000}'),n={name:"guides/knowledge-indexing-portals.md"};function d(i,t,s,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="guide-knowledge-indexing-portals" tabindex="-1">Guide: Knowledge Indexing &amp; Portals <a class="header-anchor" href="#guide-knowledge-indexing-portals" aria-label="Permalink to &quot;Guide: Knowledge Indexing &amp; Portals&quot;">​</a></h1><p><strong>Decision:</strong> How do humans browse ADRs/specs, and how do AI agents retrieve them?</p><p><strong>Full catalog:</strong> <a href="./../ai-toolkit.html">AI toolkit</a> — MCP, portals, ADR, specs, and retrieval tools.</p><p>Related: <a href="./../planning-and-adr.html">planning-and-adr.md</a> · <a href="./../sops/SOP-009-artifact-publish.html">SOP-009</a></p><hr><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>ADRs and specs are <strong>non-production artifacts</strong>. They must be discoverable by people, retrievable by AI agents, and changeable only through review (typically Git PRs).</p><hr><h2 id="options-compared" tabindex="-1">Options compared <a class="header-anchor" href="#options-compared" aria-label="Permalink to &quot;Options compared&quot;">​</a></h2><h3 id="git-only-no-portal" tabindex="-1">Git only (no portal) <a class="header-anchor" href="#git-only-no-portal" aria-label="Permalink to &quot;Git only (no portal)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Zero extra infra</td><td>Poor browse UX for non-Git users</td></tr><tr><td>Agents can read repo directly</td><td>Large monorepos → noisy retrieval</td></tr></tbody></table><p><strong>Fit:</strong> Small teams; early adoption.</p><hr><h3 id="static-site-s3-cloudfront-from-ci" tabindex="-1">Static site (S3 + CloudFront from CI) <a class="header-anchor" href="#static-site-s3-cloudfront-from-ci" aria-label="Permalink to &quot;Static site (S3 + CloudFront from CI)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Cheap; fast; read-only</td><td>Search is basic unless you add an index</td></tr><tr><td>Good for auditors</td><td>Another URL to maintain</td></tr></tbody></table><p><strong>Fit:</strong> ADR library + rendered specs; pair with search below.</p><hr><h3 id="backstage-techdocs-catalog" tabindex="-1">Backstage (TechDocs + catalog) <a class="header-anchor" href="#backstage-techdocs-catalog" aria-label="Permalink to &quot;Backstage (TechDocs + catalog)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Links services ↔ ADRs ↔ specs</td><td>Platform team must operate Backstage</td></tr><tr><td>Industry standard for eng portals</td><td>Initial setup cost</td></tr></tbody></table><p><strong>Fit:</strong> Organizations with many services and developers.</p><hr><h3 id="confluence-or-sharepoint" tabindex="-1">Confluence (or SharePoint) <a class="header-anchor" href="#confluence-or-sharepoint" aria-label="Permalink to &quot;Confluence (or SharePoint)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>PM and legal teams already use it</td><td>Easily becomes stale source of truth</td></tr><tr><td>Familiar approval workflows</td><td>Weak agent indexing without sync</td></tr></tbody></table><p><strong>Fit:</strong> <strong>Mirror only</strong>, not canonical store.</p><hr><h3 id="opensearch" tabindex="-1">OpenSearch <a class="header-anchor" href="#opensearch" aria-label="Permalink to &quot;OpenSearch&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Full-text + semantic search; RAG-friendly</td><td>Operational cost (cluster or Serverless)</td></tr><tr><td>Filter index to Accepted/Approved artifacts</td><td>Reindex pipeline required on merge</td></tr></tbody></table><p><strong>Fit:</strong> Medium–large orgs; primary RAG backend.</p><hr><h3 id="amazon-kendra" tabindex="-1">Amazon Kendra <a class="header-anchor" href="#amazon-kendra" aria-label="Permalink to &quot;Amazon Kendra&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Managed enterprise search</td><td>Higher cost at scale</td></tr><tr><td>AWS-native connectors</td><td>Less customizable than OpenSearch for bespoke RAG</td></tr></tbody></table><p><strong>Fit:</strong> Teams wanting managed search without operating OpenSearch.</p><hr><h3 id="mcp-server-over-git-or-index" tabindex="-1">MCP server over Git or index <a class="header-anchor" href="#mcp-server-over-git-or-index" aria-label="Permalink to &quot;MCP server over Git or index&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>IDE agents call <code>search_adr</code>, <code>get_spec</code></td><td>You build and operate MCP in <strong>your</strong> platform (not this repo)</td></tr><tr><td>Precise retrieval</td><td>Extra availability dependency</td></tr></tbody></table><p><strong>Fit:</strong> Cursor-heavy teams; complements search index.</p><hr><h2 id="combination-patterns" tabindex="-1">Combination patterns <a class="header-anchor" href="#combination-patterns" aria-label="Permalink to &quot;Combination patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Components</th><th>When</th></tr></thead><tbody><tr><td><strong>Minimal</strong></td><td>Git + MCP reading Git</td><td>&lt; 20 engineers</td></tr><tr><td><strong>Standard</strong></td><td>Git + Backstage + OpenSearch + MCP</td><td>Most enterprise teams</td></tr><tr><td><strong>Compliance-heavy</strong></td><td>Above + static site + Confluence mirror</td><td>Regulated industries</td></tr></tbody></table><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Confluence as canonical</strong></td><td>AI and devs read stale docs</td><td>Git merge triggers publish</td></tr><tr><td><strong>Indexing draft ADRs</strong></td><td>Agents implement rejected ideas</td><td>Filter ingest by <code>accepted</code> / <code>approved</code></td></tr><tr><td><strong>Whole-repo embedding</strong></td><td>Irrelevant RAG chunks</td><td>Index only <code>docs/adr</code>, <code>specs/</code></td></tr><tr><td><strong>No PR review on ADR changes</strong></td><td>Silent architecture shifts</td><td>ADRs change only via PR</td></tr><tr><td><strong>Portal without ownership</strong></td><td>Broken TechDocs</td><td>Platform SLO on publish pipeline</td></tr><tr><td><strong>Duplicate ADR in wiki and Git</strong></td><td>Two versions diverge</td><td>Sync Git → wiki one direction</td></tr><tr><td><strong>MCP pointing at wiki</strong></td><td>Wrong version in agent context</td><td>MCP reads index or pinned Git SHA</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Git as canonical → on merge, publish to Backstage + OpenSearch (Accepted/Approved only) → MCP for IDE agents. Add Confluence mirror only if non-dev stakeholders require it.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./planning-adr-specs.html">Planning, ADR &amp; specs</a> · <a href="./ai-coding-tools.html">AI coding tools</a></li></ul>',48)])])}const b=e(n,[["render",d]]);export{g as __pageData,b as default};
